import { useRef, useState } from "react";
import { FaTimes } from "react-icons/fa";

import {FetchApi}  from "../../../Controller/FetchApi";
const {consultaGet} = FetchApi;

//para escolher o cliente execute a função props.escolherCliente(cliente)
export default function BuscaDetalhadaClientes(props){
    const endereco = useRef('');
    const cidade = useRef('');
    const data = useRef('');

    const [listaClientes, setListaClientes] = useState([]);

    async function handlerBuscaDetalhadaCliente(){
        if(endereco.current.value.length > 2 || cidade.current.value.length > 2 || data.current.value !== ''){
            console.log((`/clientes/${endereco.current?.value},${endereco.current?.value},${cidade.current?.value},${data.current.value}`));
            let listaClientesProv = await consultaGet(`/clientes/${endereco.current?.value},${cidade.current?.value},${data.current.value}`);
            console.log(listaClientesProv);
            setListaClientes(listaClientesProv.resultado);
        }else{
            setListaClientes([]);
        }
    }
    
    return(
        <div className="miniJanelaDeEscolha">                        
            <fieldset className="fieldset">
                <div className="flexNaoResponsivo">
                    <h4>Diga algo que sabe do cliente:</h4>
                    <FaTimes size={30}  onClick={props.abrirFormFiltrarCliente}/>
                </div>
                <input type='number' ref={cpf} onClick={(e) => e.target.select()} onChange={handlerBuscaDetalhadaCliente} className='form-control' placeholder='CPF' />
                <input type='text' ref={endereco} onClick={(e) => e.target.select()} onChange={handlerBuscaDetalhadaCliente} className='form-control' placeholder='Endereço' />
                <input type='text' ref={cidade} onClick={(e) => e.target.select()} onChange={handlerBuscaDetalhadaCliente} className='form-control' placeholder='Cidade' />
                <label>Data de algum evento</label>
                <input  ref={data} className='form-control' onChange={handlerBuscaDetalhadaCliente} type='date'/>
            </fieldset>
            <div>
                {listaClientes && listaClientes.length > 0? <h5 className="espacoAntes">Clientes encontrados:</h5>: ''}
                
                {listaClientes?.map((cliente, indice) => {
                    return(
                        <div key={indice} onClick={() => props.escolherCliente(cliente)}>
                            {cliente.nome}
                            <hr/>
                        </div>
                    )
                })}
            </div>
        </div>
    );
}
